const MODULE3_LESSONS = buildModule3Lessons(MODULE3_SOURCE_TEXT, MODULE3_LESSON_META);

function buildModule3Lessons(sourceText, lessonMeta) {
  const normalized = sourceText
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/________________________________________/g, '')
    .trim();

  const lessonStarts = [];
  const lessonRegex = /^Урок\.?\s*([^\n]*)/gmi;
  let match;

  while ((match = lessonRegex.exec(normalized)) !== null) {
    lessonStarts.push({ index: match.index, heading: match[0].trim() });
  }

  return lessonStarts.map((start, index) => {
    const meta = lessonMeta[index] || {
      id: `lesson${index + 1}`,
      icon: '💬',
      title: cleanLessonTitle(start.heading),
      shortTitle: cleanLessonTitle(start.heading),
    };
    const nextStart = lessonStarts[index + 1];
    const rawLesson = normalized.slice(start.index, nextStart ? nextStart.index : normalized.length).trim();
    const blocks = splitLessonIntoBlocks(rawLesson, meta.title);
    const intro = getLessonIntro(blocks, meta.title);

    return {
      id: meta.id,
      icon: meta.icon,
      title: meta.title,
      shortTitle: meta.shortTitle || meta.title,
      intro,
      blocks,
    };
  });
}

function splitLessonIntoBlocks(rawLesson, lessonTitle) {
  const parts = rawLesson
    .split(/\n\s*Кнопка\s+«?Далее»?\s*\n/gi)
    .map(part => part.trim())
    .filter(Boolean);

  const blocks = parts.map((part, index) => {
    const cleaned = index === 0
      ? part.replace(/^Урок\.?\s*[^\n]*\n?/i, '').trim()
      : part;
    const title = getBlockTitle(cleaned, index, lessonTitle);
    const htmlText = removeRepeatedBlockTitle(cleaned, title);
    const isMainThought = isMainThoughtTitle(title);
    const isExercise = isExerciseTitle(title);
    const isBirthdayChoice = /^Задание:\s*выбери лучшее поздравление/i.test(title);
    const isAuthorMiniTest = /^Мини-тест:\s*«?Какой ты автор/i.test(title);
    const isDuplicateLessonTitle = index === 0 && replaceBlockWord(title) === replaceBlockWord(lessonTitle);
    const outputTitle = lessonTitle === 'Пост в соцсетях' && /^Часть 3\.\s*Главная мысль/i.test(title)
      ? 'Главная мысль о стиле'
      : title;

    return {
      type: isMainThought ? 'main-thought' : isAuthorMiniTest ? 'task' : getBlockType(htmlText, index),
      title: replaceBlockWord(outputTitle),
      hideTitle: isMainThought || isExercise || isBirthdayChoice || isAuthorMiniTest || isDuplicateLessonTitle,
      html: isMainThought
        ? formatMainThoughtText(htmlText)
        : isAuthorMiniTest
          ? formatAuthorMiniTest()
          : isBirthdayChoice
            ? formatBirthdayGreetingChoice()
            : isExercise
              ? formatExerciseText(title, htmlText, lessonTitle)
              : formatModule3Text(htmlText, title, lessonTitle),
    };
  });

  const enrichedBlocks = lessonTitle === 'Пост в соцсетях'
    ? insertLesson3InteractiveBlocks(blocks)
    : lessonTitle === 'Лайк и комментарий'
      ? insertLesson4InteractiveBlocks(blocks)
      : lessonTitle === 'Чашка кофе'
        ? insertLesson5InteractiveBlocks(blocks)
        : lessonTitle === 'Полезная ссылка'
          ? insertLesson6InteractiveBlocks(blocks)
          : lessonTitle === 'Звонок'
            ? insertLesson7InteractiveBlocks(blocks)
            : lessonTitle === 'Обновление базы контактов'
              ? insertLesson8InteractiveBlocks(blocks)
              : blocks;

  // Для интерактивного мини-теста результаты показываются сразу после выбора
  // ответов, поэтому отдельный текстовый блок "Подсчёт результатов" скрываем.
  return enrichedBlocks.filter(block => !/^Подсчёт результатов/i.test(block.title) || !/Какой ты автор/i.test(rawLesson));
}

function insertLesson3InteractiveBlocks(blocks) {
  const result = [];

  blocks.forEach(block => {
    // В исходном тексте тест "Какой ты автор?" стоит позже.
    // В интерфейсе урока он должен идти сразу после блока "Стиль 3. Оптимист",
    // поэтому старое место пропускаем, а ниже вставляем тест вручную.
    if (/^Мини-тест:\s*«?Какой ты автор/i.test(block.title)) return;

    result.push(block);

    if (block.title === 'Как выбрать стратегию') {
      result.push({
        type: 'task',
        title: 'Мини-тест: «Какая стратегия — твоя?»',
        hideTitle: true,
        html: formatStrategyMiniTest(),
      });
    }

    if (block.title === 'Стиль 3. Оптимист') {
      result.push({
        type: 'task',
        title: 'Мини-тест: «Какой ты автор?»',
        hideTitle: true,
        html: formatAuthorMiniTest(),
      });

      result.push({
        type: 'task',
        title: 'Часть 3. Стратегия × Стиль = твой почерк',
        hideTitle: true,
        html: formatStrategyStyleMatrix(),
      });
    }
  });

  return result;
}

function insertLesson4InteractiveBlocks(blocks) {
  return blocks
    .filter(block => !/Анти-нетворкинг/i.test(stripHtml(block.html)))
    .map(block => {
      if (block.title === 'Задание: 4 поста в твоей ленте') {
        return {
          ...block,
          html: formatLesson4Scenario(LIKE_COMMENT_SCENARIOS[0]),
        };
      }

      const scenario = LIKE_COMMENT_SCENARIOS.find(item => block.title === item.title);
      if (scenario) {
        return {
          ...block,
          type: 'task',
          html: formatLesson4Scenario(scenario),
        };
      }

      return block;
    });
}

function insertLesson5InteractiveBlocks(blocks) {
  return blocks.map(block => {
    if (block.title === 'Задание: пишем приглашение') {
      return {
        ...block,
        type: 'task',
        html: formatInvitationScenario(),
      };
    }

    if (block.title === 'Шаблон приглашения') {
      return {
        ...block,
        html: formatInvitationTemplate(),
      };
    }

    if (block.title === 'Что делать, если отказали или не ответили') {
      const html = block.html
        .replace('Если не ответили вообще, то это не провал.', '<strong>Если не ответили вообще, то это не провал.</strong>')
        .replace('Если снова молчание, то просто отпусти.', '<strong>Если снова молчание, то просто отпусти.</strong>');

      return {
        ...block,
        html: `<div class="m3-response-card">${html}</div>`,
      };
    }

    return block;
  });
}

function insertLesson6InteractiveBlocks(blocks) {
  return blocks
    .filter(block => !/^Контакт\s*[23]\./i.test(block.title))
    .map(block => {
      if (block.title === 'Задание: 5 контактов из твоей базы') {
        return {
          ...block,
          title: 'Задание: 3 контакта из твоей базы',
          type: 'task',
          html: formatUsefulLinkScenarios(),
        };
      }

      if (/^(Продолжение|Идеальная частота касаний)$/i.test(block.title) && /Идеальная частота касаний|Сколько раз в год касаться/i.test(stripHtml(block.html))) {
        return {
          ...block,
          title: 'Идеальная частота касаний',
          type: 'task',
          html: formatTouchFrequencySlider(),
        };
      }

      return block;
    });
}

/**
 * Урок «Звонок»: убираем устаревшие блоки, вставляем интерактивы (тест, матрица+бегунок, 3 ситуации).
 */
function insertLesson7InteractiveBlocks(blocks) {
  const filtered = blocks.filter(block => {
    const t = block.title || '';
    const plain = stripHtml(block.html);
    if (/Скрытый герой/i.test(t) || /^Скрытый герой/i.test(plain.trim())) return false;
    if (/Часть 4\.\s*Старомодные жесты/i.test(t)) return false;
    if (/Старомодные жесты, которые работают как ядерное оружие/i.test(plain)) return false;
    return true;
  });

  return filtered.map(block => {
    if (/Часть 1\.\s*Большая дилемма/i.test(block.title)) {
      return {
        ...block,
        type: 'task',
        html: formatCallWithoutWarningInteractive(),
      };
    }

    if (/Матрица «Писать или звонить/i.test(block.title)) {
      return {
        ...block,
        title: 'Матрица «Писать или звонить?»',
        html: formatWriteOrCallMatrixSection(),
      };
    }

    if (/Мини-интерактив/i.test(block.title)) {
      return {
        ...block,
        title: 'Мини-интерактив: 3 ситуации: текст, голосовое или звонок?',
        type: 'task',
        html: formatLesson7ChannelSituations(),
      };
    }

    return block;
  });
}

/** Урок «Обновление базы контактов»: интерактивы, аккордеон уровней, круги, карточки. */
function stripLesson8IntroPhoneParagraph(html) {
  return html.replace(
    /<p>[\s\S]*?Открой телефонную книгу прямо сейчас\.[\s\S]*?<\/p>\s*/i,
    '',
  );
}

function insertLesson8InteractiveBlocks(blocks) {
  const lessonTitle = 'Обновление базы контактов';
  return blocks.flatMap(block => {
    const t = block.title || '';

    if (/^Главная мысль курса/i.test(t)) {
      return [];
    }

    if (t === lessonTitle) {
      return [{ ...block, html: stripLesson8IntroPhoneParagraph(block.html) }];
    }

    if (/Часть 1\./i.test(t)) {
      return [{ ...block, html: formatLesson8Part1WeakTies() }];
    }
    if (/Часть 2\./i.test(t)) {
      return [{ ...block, html: formatLesson8Part2PyramidCircles() }];
    }
    if (
      /Ключевой принцип пирамиды/i.test(t) ||
      (/^Продолжение$/i.test(t) && /Контакты переходят между кругами/i.test(stripHtml(block.html)))
    ) {
      return [{ ...block, hideTitle: true, html: formatLesson8KeyPrincipleBlock() }];
    }
    if (/Часть 3\./i.test(t)) {
      return [{ ...block, html: formatLesson8ContactFieldsBlock() }];
    }
    if (
      /Магический вопрос/i.test(t) ||
      (/^Продолжение$/i.test(t) && /открою эту запись через год/i.test(stripHtml(block.html)))
    ) {
      return [{ ...block, hideTitle: true, html: formatLesson8MagicQuestionBlock() }];
    }
    if (/Часть 4\./i.test(t)) {
      return [{ ...block, html: formatLesson8ToolsAccordion() }];
    }
    if (
      (/Главное правило выбора инструмента/i.test(t) ||
        (/^Продолжение$/i.test(t) && /Главное правило выбора инструмента/i.test(stripHtml(block.html)))) &&
      /начни с того уровня/i.test(stripHtml(block.html))
    ) {
      return [{ ...block, hideTitle: true, html: formatLesson8InstrumentRuleBlock() }];
    }
    if (/Часть 5\./i.test(t)) {
      return [{ ...block, html: formatLesson8RitualFlipCards() }];
    }
    if (/^ПРАКТИКА:/i.test(t)) {
      return [{ ...block, type: 'task', html: formatLesson8PracticeSteps() }];
    }
    if (
      /Признаки, что твоя база работает/i.test(t) ||
      (/^Продолжение$/i.test(t) && /Через 3–6 месяцев системной работы/i.test(stripHtml(block.html)))
    ) {
      return [{ ...block, hideTitle: true, html: formatLesson8SignsBlock(block.html) }];
    }
    if (
      /Главный секрет нетворкинга/i.test(t) ||
      (/^Продолжение$/i.test(t) && /Ты не построишь сильную сеть за месяц/i.test(stripHtml(block.html)))
    ) {
      return [{ ...block, hideTitle: true, html: formatLesson8ClosingSecretBlock() }];
    }

    return [block];
  });
}

