function handleLesson8UiClick(event) {
  const circleBtn = event.target.closest('[data-l8-circle]');
  const root = circleBtn?.closest('[data-l8-circles-root]');
  if (circleBtn && root) {
    const key = circleBtn.getAttribute('data-l8-circle');
    root.querySelectorAll('[data-l8-circle]').forEach(btn => btn.classList.toggle('is-active', btn === circleBtn));
    const panel = root.querySelector('[data-l8-circle-panel]');
    if (panel && LESSON8_CIRCLE_PANEL[key]) panel.innerHTML = LESSON8_CIRCLE_PANEL[key];
    return;
  }

  const accBtn = event.target.closest('[data-l8-acc-btn]');
  if (accBtn) {
    const item = accBtn.closest('.m3-l8-acc-item');
    const accordion = accBtn.closest('.m3-l8-accordion');
    if (!item || !accordion) return;
    const willOpen = !item.classList.contains('is-open');
    accordion.querySelectorAll('.m3-l8-acc-item').forEach(i => {
      i.classList.remove('is-open');
      const b = i.querySelector('[data-l8-acc-btn]');
      const p = i.querySelector('.m3-l8-acc-panel');
      if (b) b.setAttribute('aria-expanded', 'false');
      if (p) p.hidden = true;
    });
    if (willOpen) {
      item.classList.add('is-open');
      accBtn.setAttribute('aria-expanded', 'true');
      const panel = item.querySelector('.m3-l8-acc-panel');
      if (panel) panel.hidden = false;
    }
    return;
  }

  const flip = event.target.closest('[data-l8-flip]');
  if (flip) {
    const on = flip.classList.toggle('is-flipped');
    flip.setAttribute('aria-pressed', on ? 'true' : 'false');
  }
}

function handleLesson8FlipKey(event) {
  if (event.key !== 'Enter' && event.key !== ' ') return;
  const flip = event.target.closest('[data-l8-flip]');
  if (!flip || event.target !== flip) return;
  event.preventDefault();
  flip.click();
}

