function handleChoiceClick(event) {
  const button = event.target.closest('.m3-choice-button');
  if (!button) return;

  const option = button.closest('.m3-choice-option');
  const task = button.closest('.m3-choice-task');
  const feedback = option.querySelector('.m3-choice-feedback');
  const isCorrect = option.dataset.correct === 'true';
  const unlockWithAnyAnswer = task?.dataset.choiceUnlock === 'any';

  task.querySelectorAll('.m3-choice-option').forEach(item => {
    item.classList.remove('selected', 'wrong', 'correct', 'reflection-pick');
    const itemFeedback = item.querySelector('.m3-choice-feedback');
    if (itemFeedback) itemFeedback.classList.add('hidden');
  });

  const isReflection = task?.classList.contains('m3-reflection-feedback');
  option.classList.add(
    'selected',
    isReflection ? 'reflection-pick' : isCorrect ? 'correct' : 'wrong',
  );
  feedback.classList.remove('hidden');

  if (task?.dataset.choiceTask === 'call-dilemma') {
    task.querySelector('.m3-call-dilemma-after')?.classList.remove('hidden');
  }

  if (unlockWithAnyAnswer) {
    task.classList.add('answered-correct');
    updateLessonActionButtons();
    return;
  }

  if (isCorrect) {
    task.classList.add('answered-correct');
    revealNextUsefulLinkScenario(task);
    updateLessonActionButtons();
  }
}

function revealNextUsefulLinkScenario(currentTask) {
  const wrapper = currentTask.closest('.m3-useful-link-task');
  if (!wrapper) return;

  const tasks = Array.from(wrapper.querySelectorAll('.m3-feed-situation'));
  const nextTask = tasks[tasks.indexOf(currentTask) + 1];
  if (nextTask) nextTask.classList.remove('hidden');
}

function handleQuizClick(event) {
  const button = event.target.closest('.m3-quiz-option');
  if (!button || button.classList.contains('m3-strategy-option')) return;

  const question = button.closest('.m3-quiz-question');
  const quiz = button.closest('.m3-quiz');
  question.dataset.selected = button.dataset.value;

  question.querySelectorAll('.m3-quiz-option').forEach(option => {
    option.classList.toggle('selected', option === button);
  });

  const questions = Array.from(quiz.querySelectorAll('.m3-quiz-question'));
  revealNextQuizQuestion(questions, question);
  const selected = questions
    .map(item => item.dataset.selected)
    .filter(Boolean);

  if (selected.length !== questions.length) return;

  const counts = selected.reduce((acc, value) => {
    acc[value] = (acc[value] || 0) + 1;
    return acc;
  }, {});
  const winner = ['A', 'B', 'C', 'D']
    .sort((left, right) => (counts[right] || 0) - (counts[left] || 0))[0];
  const result = AUTHOR_TEST_RESULTS[winner];
  const resultBox = quiz.querySelector('.m3-quiz-result');

  resultBox.innerHTML = `
    <div class="m3-callout m3-callout-analysis">
      <div class="m3-callout-title">Обратная связь</div>
      <p><strong>${result.title}</strong></p>
      <p>${result.text}</p>
    </div>
  `;
  resultBox.classList.remove('hidden');
}

function revealNextQuizQuestion(questions, currentQuestion) {
  const currentIndex = questions.indexOf(currentQuestion);
  const nextQuestion = questions[currentIndex + 1];
  if (nextQuestion) nextQuestion.classList.remove('hidden');
}

function handleStrategyTestClick(event) {
  const button = event.target.closest('.m3-strategy-option');
  if (!button) return;

  const question = button.closest('.m3-quiz-question');
  const test = button.closest('.m3-strategy-test');
  question.dataset.selected = button.dataset.value;

  question.querySelectorAll('.m3-strategy-option').forEach(option => {
    option.classList.toggle('selected', option === button);
  });

  const questions = Array.from(test.querySelectorAll('.m3-quiz-question'));
  revealNextQuizQuestion(questions, question);
  const selected = questions
    .map(item => item.dataset.selected)
    .filter(Boolean);

  if (selected.length !== questions.length) return;

  const counts = selected.reduce((acc, value) => {
    acc[value] = (acc[value] || 0) + 1;
    return acc;
  }, {});
  const winner = ['A', 'B', 'C', 'D']
    .sort((left, right) => (counts[right] || 0) - (counts[left] || 0))[0];
  const result = STRATEGY_TEST_RESULTS[winner];
  const resultBox = test.querySelector('.m3-strategy-result');

  resultBox.innerHTML = `
    <div class="m3-callout m3-callout-analysis">
      <div class="m3-callout-title">Расшифровка</div>
      <p><strong>Больше ${winner} → ${result.title}</strong></p>
      <p>${inlineFormatNoLabel(result.text)}</p>
      <p><strong>Что делать:</strong> ${inlineFormatNoLabel(result.action)}</p>
      <p><strong>Подвох:</strong> ${inlineFormatNoLabel(result.trap)}</p>
    </div>
  `;
  resultBox.classList.remove('hidden');
}

function handleMatrixClick(event) {
  const reset = event.target.closest('.m3-matrix-reset');
  if (reset) {
    const matrix = reset.closest('.m3-style-matrix');
    matrix.querySelectorAll('.m3-matrix-cell').forEach(cell => cell.classList.remove('selected'));
    matrix.querySelector('.m3-matrix-output').innerHTML = '<p class="m3-matrix-placeholder">👆 Выбери ячейку, чтобы увидеть пример поста</p>';
    reset.classList.add('hidden');
    return;
  }

  const button = event.target.closest('.m3-matrix-cell');
  if (!button) return;

  const matrix = button.closest('.m3-style-matrix');
  const selected = STRATEGY_STYLE_MATRIX.find(item => item.title === button.dataset.title);
  if (!selected) return;

  matrix.querySelectorAll('.m3-matrix-cell').forEach(cell => cell.classList.remove('selected'));
  button.classList.add('selected');
  matrix.querySelector('.m3-matrix-reset').classList.remove('hidden');
  matrix.querySelector('.m3-matrix-output').innerHTML = `
    <article class="m3-matrix-post">
      <h4>${escapeHtml(selected.title)}</h4>
      <p class="m3-matrix-context">${escapeHtml(selected.context)}</p>
      <blockquote>${selected.post.split('\n').map(line => `<p>${inlineFormatNoLabel(line)}</p>`).join('')}</blockquote>
      <div class="m3-callout m3-callout-analysis">
        <div class="m3-callout-title">Почему это работает</div>
        <p>${inlineFormatNoLabel(selected.why)}</p>
      </div>
    </article>
  `;
}

function handleTouchSliderInput(event) {
  const input = event.target.closest('.m3-touch-range');
  if (!input) return;

  const slider = input.closest('.m3-touch-slider');
  const level = TOUCH_FREQUENCY_LEVELS[Number(input.value)] || TOUCH_FREQUENCY_LEVELS[0];

  slider.querySelector('.m3-touch-level').textContent = level.title;
  slider.querySelector('.m3-touch-frequency').textContent = level.frequency;
  slider.querySelector('.m3-touch-result p').textContent = level.note;
}

/** Бегунок срочности в матрице «Писать или звонить?» (урок Звонок). */
function handleWriteCallUrgencyInput(event) {
  const input = event.target.closest('.m3-write-call-slider .m3-urgency-range');
  if (!input) return;

  const card = input.closest('.m3-write-call-matrix-card');
  const table = card?.querySelector('.m3-write-call-table');
  const readout = card?.querySelector('[data-urgency-readout]');
  if (!table || !readout) return;

  const v = Number(input.value);
  const texts = [
    'Низкая срочность: спокойный текст — договорённости, ссылки, уточнения без напряжения.',
    'Средняя срочность: ответ желателен сегодня, без крайней паники. При низкой эмоциональности чаще остаёшься в чате с дедлайном и пометкой «важно» / «срочно»; при высокой — голос или звонок могут быть уместнее, чем длинная переписка.',
    'Высокая срочность: если тема эмоционально тяжёлая — голос или звонок; если сухая фактура, но ответ нужен сейчас — короткое сообщение с жёстким дедлайном или согласованный звонок.',
  ];
  readout.textContent = texts[v] || texts[0];

  table.classList.remove('urgency-low', 'urgency-mid', 'urgency-high');
  table.classList.add(v === 0 ? 'urgency-low' : v === 1 ? 'urgency-mid' : 'urgency-high');
}

function setupCalendarImage() {
  // Сначала подписываемся на load, потом задаём src.
  // Иначе при быстрой загрузке браузер может пропустить событие.
  els.calendarImg.addEventListener('load', positionPlacedIcons);
  els.calendarImg.addEventListener('error', () => {
    els.calendarImg.classList.add('is-missing');
    els.calendarFallback.classList.add('visible');
  });
  els.calendarImg.src = MODULE3_CALENDAR_IMAGE;

  if (els.introCalendarImg) {
    els.introCalendarImg.src = MODULE3_CALENDAR_IMAGE;
    els.introCalendarImg.addEventListener('error', () => {
      els.introCalendarImg.classList.add('is-missing');
    });
  }
}

function openIntroModal() {
  if (!els.introModal) {
    showScreen('m3-calendar');
    return;
  }
  els.introModal.classList.remove('hidden');
  els.introModal.setAttribute('aria-hidden', 'false');
}

function closeIntroModal() {
  if (!els.introModal) return;
  els.introModal.classList.add('hidden');
  els.introModal.setAttribute('aria-hidden', 'true');
}

function loadProgress() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return;

    const saved = JSON.parse(raw);
    m3State.completedLessonIds = Array.isArray(saved.completedLessonIds)
      ? saved.completedLessonIds.filter(id => MODULE3_LESSONS.some(lesson => lesson.id === id))
      : [];
  } catch (e) {
    // Если сохранение сломалось, начинаем модуль заново, а не ломаем страницу.
    m3State.completedLessonIds = [];
  }
}

function saveProgress() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify({
    completedLessonIds: m3State.completedLessonIds,
  }));
}

function renderCoverPills() {
  els.coverLessons.innerHTML = MODULE3_LESSONS
    .map(lesson => `<span class="m3-pill">${lesson.shortTitle || lesson.title}</span>`)
    .join('');
}

function renderLessonIcons() {
  els.iconList.innerHTML = MODULE3_LESSONS.map((lesson, index) => {
    const completed = isLessonCompleted(lesson.id);
    const active = isLessonAvailable(index);
    const status = completed
      ? '✓ Изучен · нажми, чтобы открыть'
      : active
        ? (isModule3MobileViewport() ? 'Нажми, чтобы открыть урок' : 'Перенеси на календарь')
        : 'Откроется позже';
    const className = [
      'm3-lesson-card',
      completed ? 'completed' : '',
      !active && !completed ? 'locked' : '',
    ].join(' ').trim();

    return `
      <article class="${className}"
               data-lesson-id="${lesson.id}"
               draggable="${active && !completed}">
        <div class="m3-lesson-icon">${lesson.icon}</div>
        <div>
          <div class="m3-lesson-card-title">${lesson.title}</div>
          <div class="m3-lesson-card-status">${status}</div>
        </div>
      </article>
    `;
  }).join('');

  document.querySelectorAll('.m3-lesson-card').forEach(card => {
    card.addEventListener('dragstart', handleDragStart);
    card.addEventListener('click', () => {
      const lessonId = card.dataset.lessonId;
      const lessonIndex = MODULE3_LESSONS.findIndex(lesson => lesson.id === lessonId);

      if (isLessonCompleted(lessonId)) {
        openLesson(lessonId);
        return;
      }

      // На мобильных устройствах drag-and-drop часто неудобен.
      // Поэтому активная иконка по нажатию работает как "перенос на календарь".
      if (isLessonAvailable(lessonIndex)) {
        startLessonFromCalendar(lessonId);
      }
    });
  });
}

function renderPlacedIcons() {
  els.placedIcons.innerHTML = m3State.completedLessonIds.map((lessonId, index) => {
    const lesson = findLesson(lessonId);
    if (!lesson) return '';

    const slot = MODULE3_DATE_SLOTS[index] || MODULE3_DATE_SLOTS[MODULE3_DATE_SLOTS.length - 1];

    return `
      <div class="m3-placed-icon"
           data-lesson-id="${lesson.id}"
           data-calendar-x="${slot.x}"
           data-calendar-y="${slot.y}"
           title="${lesson.title} — ${slot.date} число">
        <span class="m3-placed-icon-date">${slot.date}</span>
        ${lesson.icon}
      </div>
    `;
  }).join('');

  positionPlacedIcons();

  els.placedIcons.querySelectorAll('.m3-placed-icon').forEach(icon => {
    icon.addEventListener('click', () => openLesson(icon.dataset.lessonId));
  });
}

function positionPlacedIcons() {
  if (!els.calendarDrop || !els.calendarImg || !els.placedIcons) return;
  if (isModule3MobileViewport()) return;

  const imageRect = getRenderedCalendarImageRect();
  const dropRect = els.calendarDrop.getBoundingClientRect();

  els.placedIcons.querySelectorAll('.m3-placed-icon').forEach(icon => {
    const x = Number(icon.dataset.calendarX);
    const y = Number(icon.dataset.calendarY);
    if (!Number.isFinite(x) || !Number.isFinite(y)) return;

    const left = imageRect.left - dropRect.left + (imageRect.width * x / 100);
    const top = imageRect.top - dropRect.top + (imageRect.height * y / 100);

    icon.style.left = `${left}px`;
    icon.style.top = `${top}px`;
  });
}

function getRenderedCalendarImageRect() {
  const dropRect = els.calendarDrop.getBoundingClientRect();

  // Если картинка не загрузилась, используем всю область календаря.
  if (els.calendarImg.classList.contains('is-missing') || !els.calendarImg.naturalWidth) {
    return {
      left: dropRect.left,
      top: dropRect.top,
      width: dropRect.width,
      height: dropRect.height,
    };
  }

  const style = window.getComputedStyle(els.calendarImg);
  const padLeft = parseFloat(style.paddingLeft) || 0;
  const padRight = parseFloat(style.paddingRight) || 0;
  const padTop = parseFloat(style.paddingTop) || 0;
  const padBottom = parseFloat(style.paddingBottom) || 0;

  const boxWidth = Math.max(dropRect.width - padLeft - padRight, 1);
  const boxHeight = Math.max(dropRect.height - padTop - padBottom, 1);
  const imageRatio = els.calendarImg.naturalWidth / els.calendarImg.naturalHeight;
  const boxRatio = boxWidth / boxHeight;

  let width = boxWidth;
  let height = boxHeight;
  let left = dropRect.left + padLeft;
  let top = dropRect.top + padTop;

  if (boxRatio > imageRatio) {
    height = boxHeight;
    width = height * imageRatio;
    left += (boxWidth - width) / 2;
  } else {
    width = boxWidth;
    height = width / imageRatio;
    top += (boxHeight - height) / 2;
  }

  return { left, top, width, height };
}

function updateProgressUI() {
  const done = m3State.completedLessonIds.length;
  const total = MODULE3_LESSONS.length;
  const pct = total ? Math.round((done / total) * 100) : 0;

  els.progressText.textContent = `${done} / ${total}`;
  els.progressFill.style.width = `${pct}%`;

  if (isModule3MobileViewport()) {
    els.dropHint.textContent = done === total ? 'Все уроки изучены' : 'Следующий урок — по иконке ниже';
  } else if (done === total) {
    els.dropHint.textContent = 'Все уроки изучены';
  } else {
    const nextLesson = MODULE3_LESSONS.find(lesson => !isLessonCompleted(lesson.id));
    els.dropHint.textContent = nextLesson
      ? `Перетащи сюда: ${nextLesson.shortTitle || nextLesson.title}`
      : 'Перетащи сюда активную иконку';
  }
}

function handleDragStart(event) {
  const lessonId = event.currentTarget.dataset.lessonId;
  const lessonIndex = MODULE3_LESSONS.findIndex(lesson => lesson.id === lessonId);

  if (!isLessonAvailable(lessonIndex) || isLessonCompleted(lessonId)) {
    event.preventDefault();
    return;
  }

  event.dataTransfer.setData('text/plain', lessonId);
  event.dataTransfer.effectAllowed = 'move';
}

function handleDragOver(event) {
  event.preventDefault();
  els.calendarDrop.classList.add('drag-over');
}

function handleDragLeave() {
  els.calendarDrop.classList.remove('drag-over');
}

function handleDrop(event) {
  event.preventDefault();
  els.calendarDrop.classList.remove('drag-over');

  const lessonId = event.dataTransfer.getData('text/plain');
  startLessonFromCalendar(lessonId);
}

function startLessonFromCalendar(lessonId) {
  const lessonIndex = MODULE3_LESSONS.findIndex(lesson => lesson.id === lessonId);

  if (lessonIndex === -1 || !isLessonAvailable(lessonIndex) || isLessonCompleted(lessonId)) {
    return;
  }

  openLesson(lessonId);
}

function openLesson(lessonId) {
  const lesson = findLesson(lessonId);
  if (!lesson) return;

  m3State.currentLessonId = lessonId;
  m3State.visibleBlockCount = 0;

  els.lessonIcon.textContent = lesson.icon;
  els.lessonKicker.textContent = `Урок ${MODULE3_LESSONS.indexOf(lesson) + 1}`;
  els.lessonTitle.textContent = lesson.title;
  els.lessonIntro.textContent = lesson.intro || '';
  els.lessonMeta.textContent = `${MODULE3_LESSONS.indexOf(lesson) + 1} / ${MODULE3_LESSONS.length}`;

  els.longreadBlocks.innerHTML = lesson.blocks.map((block, index) => `
    <section class="m3-read-block ${block.type || 'theory'}" data-block-index="${index}">
      ${block.hideTitle ? '' : `<h3>${block.title || 'Часть урока'}</h3>`}
      ${block.html || ''}
    </section>
  `).join('');

  els.nextBlockBtn.classList.remove('hidden');
  els.completeLessonBtn.classList.add('hidden');
  els.completeLessonBtn.textContent = isLessonCompleted(lessonId) ? 'Вернуться к календарю' : 'Завершить урок';
  showScreen('m3-lesson');
  revealNextBlock();
}

function revealNextBlock() {
  const lesson = findLesson(m3State.currentLessonId);
  if (!lesson) return;

  const blocks = Array.from(els.longreadBlocks.querySelectorAll('.m3-read-block'));
  const block = blocks[m3State.visibleBlockCount];
  if (!block) return;

  block.classList.add('visible');
  m3State.visibleBlockCount += 1;

  // После раскрытия блока прокручиваем к нему, чтобы лонгрид ощущался как последовательное чтение.
  setTimeout(() => {
    block.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }, 80);

  if (m3State.visibleBlockCount >= lesson.blocks.length) {
    updateLessonActionButtons();
    return;
  }

  updateLessonActionButtons();
}

function updateLessonActionButtons() {
  const lesson = findLesson(m3State.currentLessonId);
  if (!lesson) return;

  const blocks = Array.from(els.longreadBlocks.querySelectorAll('.m3-read-block'));
  const currentBlock = blocks[m3State.visibleBlockCount - 1];
  const waitingForCorrectAnswer = currentBlock?.querySelector('.m3-feed-situation:not(.answered-correct)');

  if (waitingForCorrectAnswer) {
    els.nextBlockBtn.classList.add('hidden');
    els.completeLessonBtn.classList.add('hidden');
    return;
  }

  if (m3State.visibleBlockCount >= lesson.blocks.length) {
    els.nextBlockBtn.classList.add('hidden');
    els.completeLessonBtn.classList.remove('hidden');
  } else {
    els.nextBlockBtn.classList.remove('hidden');
    els.completeLessonBtn.classList.add('hidden');
  }
}

function completeCurrentLesson() {
  const lessonId = m3State.currentLessonId;
  if (!lessonId) return;

  if (isLessonCompleted(lessonId)) {
    returnToCalendar();
    return;
  }

  m3State.completedLessonIds.push(lessonId);
  saveProgress();
  renderLessonIcons();
  renderPlacedIcons();
  updateProgressUI();

  if (isModule3Completed()) {
    showScreen('m3-calendar');
    openCompleteModal();
    return;
  }

  returnToCalendar();
}

function returnToCalendar() {
  m3State.currentLessonId = null;
  m3State.visibleBlockCount = 0;
  showScreen('m3-calendar');
}

function openCompleteModal() {
  renderModule3FinishModal();
  triggerModule3FinishConfetti();
  els.completeModal.classList.remove('hidden');
}

function finishModule3() {
  if (typeof CourseProgress !== 'undefined') {
    CourseProgress.markModule3Complete();
  } else {
    localStorage.setItem('nc_mod3_status', 'complete');
  }

  if (typeof SCORM !== 'undefined') {
    SCORM.setCompleted();
    SCORM.finish();
  }

  if (typeof CourseProgress !== 'undefined') {
    CourseProgress.navigate('map.html');
  } else {
    window.location.href = 'map.html';
  }
}

function resetModule3Progress() {
  const ok = window.confirm('Сбросить прогресс модуля 3?');
  if (!ok) return;

  closeIntroModal();

  localStorage.removeItem(STORAGE_KEY);
  m3State.completedLessonIds = [];
  m3State.currentLessonId = null;
  m3State.visibleBlockCount = 0;

  renderLessonIcons();
  renderPlacedIcons();
  updateProgressUI();
}

function showScreen(screenId) {
  document.querySelectorAll('.m3-screen').forEach(screen => {
    screen.classList.toggle('active', screen.id === screenId);
  });

  // Календарь до открытия скрыт, поэтому его размеры нельзя корректно измерить.
  // После показа экрана пересчитываем позиции иконок уже по видимой картинке.
  if (screenId === 'm3-calendar') {
    requestAnimationFrame(positionPlacedIcons);
  }

  window.scrollTo({ top: 0, behavior: 'auto' });
}

function findLesson(lessonId) {
  return MODULE3_LESSONS.find(lesson => lesson.id === lessonId);
}

function isLessonCompleted(lessonId) {
  return m3State.completedLessonIds.includes(lessonId);
}

function isLessonAvailable(index) {
  if (index < 0) return false;
  if (index === 0) return true;

  // Уроки открываются по очереди: следующий доступен после завершения предыдущего.
  // Если нужно разрешить проходить в любом порядке, замени return на true.
  const previousLesson = MODULE3_LESSONS[index - 1];
  return isLessonCompleted(previousLesson.id);
}

function isModule3Completed() {
  return MODULE3_LESSONS.every(lesson => isLessonCompleted(lesson.id));
}



